   642→		j = ldap_x_utf8_to_wc( &tmp, c );
   643→		switch (tmp >> 8) {
   644→		case 0x00:
   645→		case 0x01:
   646→		case 0x02:
   647→			if (wc00[tmp >> 6]) {
   648→				tmp = (*wc00[tmp >> 6])[tmp & 0x3f];
   649→				if (tmp & 0xff00)
   650→					*d++ = (tmp >> 8);
   651→				*d++ = tmp & 0xff;
   652→			} else {
   653→				*d++ = 0x3f;
   654→			}
   655→			break;
   656→		case 0x03:
   657→			/* swap order of non-spacing characters */
   658→			if (wc00[tmp >> 6]) {
   659→				wchar_t t2 = (*wc00[tmp >> 6])[tmp & 0x3f];
   660→				if (t2 != 0x3f) {
   661→					d[0] = d[-1];
   662→					d[-1] = t2;
   663→					d++;
   664→				} else {
   665→					*d++ = 0x3f;
   666→				}
   667→			} else {
   668→				*d++ = 0x3f;
   669→			}
   670→			break;
   671→		case 0x1e:
   672→			tmp = (*wc1e[(tmp >> 6) & 3])[tmp & 0x3f];
   673→			if (tmp & 0xff00)
   674→				*d++ = (tmp >> 8);
   675→			*d++ = tmp & 0xff;
   676→			break;
   677→		case 0x21:
   678→			if (tmp == 0x2126) {
   679→				*d++ = 0xe0;
   680→				break;
   681→			}
   682→			/* FALLTHRU */
   683→		default:
   684→			*d++ = 0x3f;
   685→			break;
   686→		}
   687→		i += j;
   688→		c += j;
   689→	}
   690→	*d = '\0';
   691→	return LDAP_SUCCESS;
   692→}
